1	const PROCESSING_FEE = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PREMIUM = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
15	
16	function computeItemPremiums(items: any[]): number {
17	  const componentCounts: Record<string, number> = {};
18	  let premium = 0;
19	
20	  for (const item of items) {
21	    if (COMPONENT_TYPES.has(item.type)) {
22	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
23	    } else {
24	      const basePremium = BASE_PREMIUM[item.type] ?? 0;
25	      let itemPremium = basePremium;
26	      if (item.cursed) {
27	        itemPremium += basePremium * 0.5;
28	      }
29	      premium += itemPremium;
30	    }
31	  }
32	
33	  for (const [type, count] of Object.entries(componentCounts)) {
34	    const unitPrice = BASE_PREMIUM[type] ?? 0;
35	    premium += count === BLOCK_SIZE ? BLOCK_PREMIUM : count * unitPrice;
36	  }
37	
38	  return premium;
39	}
40	
41	export function processScenario(scenario: any): unknown {
42	  const results = scenario.steps.map((step: any) => {
43	    return { premium: computeItemPremiums(step.items) + PROCESSING_FEE };
44	  });
45	  return { results };
46	}
